import{_ as a,o as s,c as t,ag as e}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Luồng Nghiệp Vụ — Vivu Travel","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/01b-luong-nghiep-vu.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/01b-luong-nghiep-vu.md"}'),i={name:"99-tham-khao/archive/01-nen-tang-he-thong/01b-luong-nghiep-vu.md"};function o(p,n,l,h,c,r){return s(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="luong-nghiep-vu-—-vivu-travel" tabindex="-1">Luồng Nghiệp Vụ — Vivu Travel <a class="header-anchor" href="#luong-nghiep-vu-—-vivu-travel" aria-label="Permalink to &quot;Luồng Nghiệp Vụ — Vivu Travel&quot;">​</a></h1><blockquote><p><strong>Phiên bản:</strong> 0.1 DRAFT · <strong>Ngày:</strong> 26/05/2026 · <strong>Tier:</strong> 2 (Functional)</p><p><strong>Trạng thái:</strong> ⚠️ DRAFT — chưa hoàn thiện. Nội dung được trích từ <a href="./03-thiet-ke-du-lieu-chi-tiet"><code>03-thiet-ke-du-lieu-chi-tiet.md</code></a> v2.2 (đã quá lan man) để giải phóng file Data Detail tập trung vào DB.</p><p>File này sẽ được <strong>refine + viết lại đầy đủ</strong> khi vào Đợt 4 (Thiết kế cơ bản) và Đợt sau (Thiết kế chi tiết / Phân tích nghiệp vụ). Hiện tại đây chỉ là nội dung <strong>tham khảo</strong> cho dev hiểu cách hệ thống vận hành.</p><p><strong>Trace anchor:</strong> V-01, V-02, V-05, V-09, V-10, V-12</p></blockquote><hr><h2 id="muc-luc" tabindex="-1">Mục lục <a class="header-anchor" href="#muc-luc" aria-label="Permalink to &quot;Mục lục&quot;">​</a></h2><ul><li><a href="#tóm-tắt-1-câu">Tóm tắt 1 câu</a></li><li><a href="#2-loại-tour-vivu-phase-1-phục-vụ">2 loại tour Vivu Phase 1 phục vụ</a></li><li><a href="#vì-sao-tách-2-flow-v-12">Vì sao tách 2 flow (V-12)</a></li><li><a href="#flow-series-tour--4-bước">Flow Series Tour — 4 bước</a></li><li><a href="#flow-private-tour--inquiry-request-3-bước">Flow Private Tour — Inquiry Request 3 bước</a></li><li><a href="#edge-cases">Edge cases</a></li><li><a href="#ranh-giới-ai-làm-gì">Ranh giới ai làm gì</a></li></ul><hr><h2 id="tom-tat-1-cau" tabindex="-1">Tóm tắt 1 câu <a class="header-anchor" href="#tom-tat-1-cau" aria-label="Permalink to &quot;Tóm tắt 1 câu&quot;">​</a></h2><p><strong>Khách lẻ book SERIES TOUR (qua web, ghép đoàn 15-20). Khách nhóm ≥10 người dùng INQUIRY FORM (Vivu liên hệ quote manual). Vivu nội bộ allocate HOTEL theo allotment đã contract trước (qua admin UI). Khách KHÔNG bao giờ trực tiếp book hotel ở Phase 1 (V-05 vĩnh viễn).</strong></p><hr><h2 id="_2-loai-tour-vivu-phase-1-phuc-vu" tabindex="-1">2 loại tour Vivu Phase 1 phục vụ <a class="header-anchor" href="#_2-loai-tour-vivu-phase-1-phuc-vu" aria-label="Permalink to &quot;2 loại tour Vivu Phase 1 phục vụ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Đặc điểm</th><th><strong>Series Tour (Tour ghép)</strong></th><th><strong>Private Tour (Tour riêng / Corporate)</strong></th></tr></thead><tbody><tr><td>Nguồn khách</td><td>Khách lẻ 1-4 người</td><td>Nhóm ≥10 (công ty, đại gia đình)</td></tr><tr><td>Ngày khởi hành</td><td>Vivu set trước (15/06, 22/06...)</td><td>Khách yêu cầu ngày tự do</td></tr><tr><td>Đoàn</td><td>Ghép 15-20 khách lạ</td><td>1 nhóm riêng</td></tr><tr><td>Giá</td><td>Niêm yết per-pax</td><td>Quote riêng theo nhóm</td></tr><tr><td>Booking flow</td><td><strong>Online</strong> — book trực tiếp</td><td><strong>Inquiry form</strong> → admin liên hệ quote manual</td></tr><tr><td>Schema entity chính</td><td><code>TourDeparture</code> → <code>TourBooking</code></td><td><code>InquiryRequest</code> (→ admin chốt deal → tạo <code>Booking</code> thủ công)</td></tr><tr><td>Phase 1 ratio</td><td>~70% revenue</td><td>~30% revenue (biên cao hơn)</td></tr></tbody></table><hr><h2 id="vi-sao-tach-2-flow-v-12" tabindex="-1">Vì sao tách 2 flow (V-12) <a class="header-anchor" href="#vi-sao-tach-2-flow-v-12" aria-label="Permalink to &quot;Vì sao tách 2 flow (V-12)&quot;">​</a></h2><ul><li><strong>Private Tour không thể book online</strong> vì cần custom hoá (chọn hotel theo yêu cầu, route theo yêu cầu, payment terms B2B, VAT đỏ).</li><li><strong>Series Tour không thể quote tay</strong> vì cần xử lý nhanh + thanh toán online + ghép đoàn tự động.</li><li>Trộn 2 flow → schema phức tạp, UX khó hiểu. Tách sạch → đơn giản.</li></ul><hr><h2 id="flow-series-tour-—-4-buoc" tabindex="-1">Flow Series Tour — 4 bước <a class="header-anchor" href="#flow-series-tour-—-4-buoc" aria-label="Permalink to &quot;Flow Series Tour — 4 bước&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 1 — VIVU CHUẨN BỊ (trước khi mở bán)                            │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • Founder/Ops ký contract Hotel ABC: &quot;giữ 100 phòng-đêm/tháng&quot;       │</span></span>
<span class="line"><span>│ • Admin nhập vào HotelAllotment:                                     │</span></span>
<span class="line"><span>│     hotelId=ABC, monthYear=&quot;2026-06&quot;, contractedRooms=100            │</span></span>
<span class="line"><span>│ • Admin tạo Tour Đà Lạt 4N3Đ:                                        │</span></span>
<span class="line"><span>│     - priceAdult=4.500.000, priceChild=3.300.000                    │</span></span>
<span class="line"><span>│     - TourOption: Deluxe upgrade +500k, Single supplement +1.2tr     │</span></span>
<span class="line"><span>│     - TourItinerary 3 đêm: hotelId=ABC, roomTypeNote=&quot;Twin Deluxe&quot;  │</span></span>
<span class="line"><span>│ • Admin tạo TourDeparture 15/06: max=20, min=10, deadline=08/06     │</span></span>
<span class="line"><span>│ • Publish tour lên web                                              │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 2 — KHÁCH BOOK TOUR (online, real-time)                         │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • Anh Khoa chọn tour, chọn departure 15/06                          │</span></span>
<span class="line"><span>│ • Điền: 2 adult + 1 child + chọn &quot;Deluxe upgrade&quot;                   │</span></span>
<span class="line"><span>│ • Click &quot;Thanh toán&quot; → Server Action:                                │</span></span>
<span class="line"><span>│     a. Pessimistic lock TourDeparture (FOR UPDATE)                  │</span></span>
<span class="line"><span>│     b. Check slot: bookedCount+3 &lt;= maxParticipants?                 │</span></span>
<span class="line"><span>│     c. Tính priceBreakdown JSON:                                     │</span></span>
<span class="line"><span>│        - 2 × 4.5tr (adult) = 9tr                                     │</span></span>
<span class="line"><span>│        - 1 × 3.3tr (child) = 3.3tr                                   │</span></span>
<span class="line"><span>│        - 3 × 500k (Deluxe option, per_pax) = 1.5tr                  │</span></span>
<span class="line"><span>│        - Total: 13.8tr                                               │</span></span>
<span class="line"><span>│     d. Tạo Booking(status=PENDING, paymentDeadline=NOW+15min)       │</span></span>
<span class="line"><span>│     e. Tăng bookedCount += 3                                         │</span></span>
<span class="line"><span>│     f. Redirect tới VNPay                                            │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│ • Anh Khoa trả tiền VNPay → webhook → Booking.status=PAID            │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 3 — VIVU ALLOCATE PHÒNG (admin UI, semi-manual)                 │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • Admin Vivu thấy Booking PAID mới trên Dashboard L0                │</span></span>
<span class="line"><span>│ • Admin tính: 3 người → 2 phòng Twin (2+1 share)                    │</span></span>
<span class="line"><span>│ • Admin vào trang HotelAllotment tháng 6:                            │</span></span>
<span class="line"><span>│     usedRooms += (2 phòng × 3 đêm) = 6                              │</span></span>
<span class="line"><span>│ • Admin email/call Hotel ABC: &quot;đặt 2 Twin Deluxe 15-18/06 cho       │</span></span>
<span class="line"><span>│   khách Khoa, ref booking VV-001&quot;                                   │</span></span>
<span class="line"><span>│ • Hotel ABC confirm → Admin update Booking.status=CONFIRMED         │</span></span>
<span class="line"><span>│ • (Phase 1.5+: hệ thống auto email Hotel khi booking PAID)          │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 4 — TOUR DIỄN RA                                                │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • 15/06: Anh Khoa lên xe Vivu → check-in Hotel ABC                  │</span></span>
<span class="line"><span>│ • 18/06: tour kết thúc → Booking.status=COMPLETED                    │</span></span>
<span class="line"><span>│ • Admin update TourDeparture.actualCostPerPax (cho V-08 reporting)   │</span></span>
<span class="line"><span>│ • Cuối tháng: Vivu invoice/pay Hotel ABC theo usedRooms              │</span></span>
<span class="line"><span>│ • Email khách: link review tour (chỉ enable khi COMPLETED)           │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="flow-private-tour-—-inquiry-request-3-buoc" tabindex="-1">Flow Private Tour — Inquiry Request 3 bước <a class="header-anchor" href="#flow-private-tour-—-inquiry-request-3-buoc" aria-label="Permalink to &quot;Flow Private Tour — Inquiry Request 3 bước&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 1 — KHÁCH SUBMIT INQUIRY (online)                               │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • Anh Khoa (HR công ty XYZ) vào trang tour Đà Lạt 4N3Đ              │</span></span>
<span class="line"><span>│ • Thấy CTA &quot;Đặt tour cho công ty / nhóm riêng (10+ người)&quot;          │</span></span>
<span class="line"><span>│ • Click → form mở:                                                   │</span></span>
<span class="line"><span>│     - Tên + email + phone                                            │</span></span>
<span class="line"><span>│     - Tên công ty: XYZ                                               │</span></span>
<span class="line"><span>│     - Số người: 40                                                   │</span></span>
<span class="line"><span>│     - Ngày dự kiến: &quot;tuần 2 tháng 6, linh hoạt&quot;                     │</span></span>
<span class="line"><span>│     - Ngân sách: 200tr (optional)                                    │</span></span>
<span class="line"><span>│     - Yêu cầu chi tiết: &quot;Hotel 4★+, có gala dinner&quot;                 │</span></span>
<span class="line"><span>│ • Submit → InquiryRequest tạo status=NEW + email auto-reply         │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 2 — VIVU XỬ LÝ (admin, manual)                                  │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • Dashboard L0 hiển thị inquiry mới — assign cho Ops Linh           │</span></span>
<span class="line"><span>│ • Ops Linh gọi điện trong 24h → status=CONTACTED                     │</span></span>
<span class="line"><span>│ • Ops build quote custom (Excel): hotel + xe + guide + ăn uống      │</span></span>
<span class="line"><span>│ • Email Khoa: báo giá 5.2tr/người × 40 = 208tr → status=QUOTED      │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ BƯỚC 3 — CHỐT DEAL (ngoài hệ thống → bridge vào hệ thống)           │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ • Khoa OK quote → 2 bên ký HĐ giấy (B2B), thanh toán chuyển khoản   │</span></span>
<span class="line"><span>│ • Ops Linh tạo Booking thủ công trên hệ thống:                       │</span></span>
<span class="line"><span>│     - Tạo TourDeparture riêng cho đoàn này (max=40, custom date)    │</span></span>
<span class="line"><span>│     - Tạo Booking + TourBooking với priceBreakdown tay              │</span></span>
<span class="line"><span>│     - Link convertedBookingId của InquiryRequest → mới này          │</span></span>
<span class="line"><span>│     - InquiryRequest.status=CONFIRMED                                │</span></span>
<span class="line"><span>│ • Sau đó flow giống Series Tour: confirm hotel allotment + tour run │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><blockquote><p><strong>Note:</strong> Phase 1 Private Tour vẫn dùng <code>TourDeparture</code> model nhưng chỉ admin tạo tay (1 departure riêng cho từng nhóm). Phase 2 có thể tách model <code>PrivateBooking</code> nếu thấy cần.</p></blockquote><hr><h2 id="edge-cases" tabindex="-1">Edge cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge cases&quot;">​</a></h2><h3 id="edge-case-1-khach-bo-ngang-khi-đang-thanh-toan" tabindex="-1">Edge case 1: Khách bỏ ngang khi đang thanh toán <a class="header-anchor" href="#edge-case-1-khach-bo-ngang-khi-đang-thanh-toan" aria-label="Permalink to &quot;Edge case 1: Khách bỏ ngang khi đang thanh toán&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Khách click &quot;Thanh toán&quot; → Booking PENDING tạo + bookedCount += 3</span></span>
<span class="line"><span>2. Khách đóng browser, không quay lại VNPay</span></span>
<span class="line"><span>3. 16 phút sau, Cron job daily/5-min:</span></span>
<span class="line"><span>   SELECT booking WHERE status=PENDING AND paymentDeadline &lt; NOW()</span></span>
<span class="line"><span>4. Auto-cancel booking + giảm bookedCount -= 3 → slot release</span></span>
<span class="line"><span>5. Khách khác có thể book slot này lại</span></span></code></pre></div><h3 id="edge-case-2-departure-khong-đu-min-participants" tabindex="-1">Edge case 2: Departure không đủ min participants <a class="header-anchor" href="#edge-case-2-departure-khong-đu-min-participants" aria-label="Permalink to &quot;Edge case 2: Departure không đủ min participants&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Tour Đà Lạt 15/06: min=10, đến 08/06 (cancellationDeadline) chỉ booked 5</span></span>
<span class="line"><span>2. Admin nhận cảnh báo từ Dashboard L0</span></span>
<span class="line"><span>3. Admin quyết cancel: TourDeparture.status=CANCELLED + cancellationReason</span></span>
<span class="line"><span>4. Tất cả TourBooking của departure này → trigger refund (admin manual Phase 1)</span></span>
<span class="line"><span>5. Email khách: tour cancel, offer departure 22/06 cùng tour hoặc refund</span></span>
<span class="line"><span>6. HotelAllotment usedRooms giảm tương ứng (admin update tay)</span></span></code></pre></div><h3 id="edge-case-3-inquiry-expired-v-12" tabindex="-1">Edge case 3: Inquiry expired (V-12) <a class="header-anchor" href="#edge-case-3-inquiry-expired-v-12" aria-label="Permalink to &quot;Edge case 3: Inquiry expired (V-12)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. InquiryRequest tạo status=NEW</span></span>
<span class="line"><span>2. 30 ngày sau, không update (no admin contact, no customer response)</span></span>
<span class="line"><span>3. Cron daily job set status=EXPIRED</span></span>
<span class="line"><span>4. Admin có thể manually re-open nếu khách quay lại</span></span></code></pre></div><hr><h2 id="ranh-gioi-ai-lam-gi" tabindex="-1">Ranh giới ai làm gì <a class="header-anchor" href="#ranh-gioi-ai-lam-gi" aria-label="Permalink to &quot;Ranh giới ai làm gì&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thực thể</th><th>Track ở đâu</th><th>Ai update</th><th>Phase 1 cách thức</th></tr></thead><tbody><tr><td>Tour package</td><td><code>tours</code>, <code>tour_itineraries</code>, <code>tour_options</code>, <code>tour_departures</code></td><td>Content admin</td><td>Form admin chi tiết</td></tr><tr><td>Series Tour booking (khách)</td><td><code>bookings</code> + <code>tour_bookings</code> + <code>payments</code></td><td>Hệ thống tự động</td><td>Server Action + webhook</td></tr><tr><td><strong>Private Tour inquiry</strong></td><td><code>inquiry_requests</code></td><td>Khách submit + admin xử lý</td><td><strong>Form web → Server Action → admin manual workflow</strong></td></tr><tr><td><strong>Private Tour booking thực sự</strong></td><td><code>bookings</code> (tạo tay sau khi chốt) + link <code>inquiry.convertedBookingId</code></td><td>Ops admin</td><td>Tạo Booking + Departure riêng thủ công</td></tr><tr><td>Hotel info</td><td><code>hotels</code>, <code>rooms</code></td><td>Content admin</td><td>Form admin</td></tr><tr><td>Hotel allotment</td><td><code>hotel_allotments</code> (monthly)</td><td>Ops admin</td><td>Form admin nhập tay đầu tháng</td></tr><tr><td>Hotel booking thực sự với hotel</td><td>(ngoài hệ thống)</td><td>Ops admin → call/email hotel</td><td>Phone/email — KHÔNG track trong DB Phase 1</td></tr><tr><td>Refund khách khi cancel</td><td>(ngoài hệ thống)</td><td>Ops admin → VNPay/MoMo dashboard</td><td>Manual qua portal payment gateway</td></tr></tbody></table><blockquote><p><strong>Lưu ý (V-05 vĩnh viễn):</strong> Vivu không trở thành OTA hotel kể cả Phase 2. Mọi tương tác khách-Vivu đều qua <code>Booking + TourBooking</code>. Tương tác Vivu-hotel (allocate phòng) đi qua <code>HotelAllotment</code> (admin nhập tay)</p><ul><li>email/phone (ngoài hệ thống).</li></ul></blockquote><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ngày</th><th>Version</th><th>Thay đổi</th></tr></thead><tbody><tr><td>26/05/2026</td><td>0.1 DRAFT</td><td>Trích từ <code>03-thiet-ke-du-lieu-chi-tiet.md</code> v2.2 (lan man) để giải phóng file Data Detail. Cần refine khi vào Đợt 4 (Thiết kế cơ bản / Phân tích nghiệp vụ).</td></tr></tbody></table><hr><p><em>File này thuộc <strong>Tier 2 (Functional Design) — DRAFT</strong>. Sẽ được hoàn thiện khi vào Đợt 4. Tham khảo:</em></p><ul><li><em>Vision &amp; anchors: <a href="./00-tam-nhin"><code>00-tam-nhin.md</code></a></em></li><li><em>Personas &amp; journey: <a href="./00c-personas-user-journey"><code>00c-personas-user-journey.md</code></a></em></li><li><em>Data ERD: <a href="./02-so-do-du-lieu"><code>02-so-do-du-lieu.md</code></a></em></li><li><em>Data Detail (DB schema): <a href="./03-thiet-ke-du-lieu-chi-tiet"><code>03-thiet-ke-du-lieu-chi-tiet.md</code></a></em></li></ul>`,39)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
